1505: // tryEnqueueingBatch tries to send a batch if necessary. If sending needs to
1506: // be retried it will return true.
1507: func (q *queue) tryEnqueueingBatch(done <-chan struct{}) bool {
1508: 	q.batchMtx.Lock()
1509: 	defer q.batchMtx.Unlock()
1510: 	if len(q.batch) == 0 {
1511: 		return false
1512: 	}
1513: 
1514: 	select {
1515: 	case q.batchQueue <- q.batch:
1516: 		return false
1517: 	case <-done:
1518: 		// The shard has been hard shut down, so no more samples can be sent.
1519: 		// No need to try again as we will drop everything left in the queue.
1520: 		return false
1521: 	default:
1522: 		// The batchQueue is full, so we need to try again later.
1523: 		return true
1524: 	}
1525: }
